import $data, { $C, Guard, Container } from 'jaydata/core';
export default $data;

$data.Class.define('$data.QueryCache', null, null, {
    constructor: function (contextType, cacheKey) {
        this._queryCache = {};
        this._fix_Items = [];
        this._cacheKey = cacheKey;
    },
    _queryCache: {},
    _cacheKey: {},
    _fix_Items: {},

    reset: function () {
        $data.Trace.log('QueryCache cache reset!', this._cacheKey);
        var keys = Object.keys(this._queryCache);
        for (var i = 0; i < keys.length; i++) {
            var cache = this._queryCache[keys[i]];
            if (cache && cache.timeoutId) {
                clearTimeout(cache.timeoutId);
            }
        }

        this._fix_Items.length = 0;
        this._queryCache = { };
    },

    hasCacheForQuery: function (query) {
        try {
            var key = this._getCacheKey(query);
            return this._queryCache[key] ? true : false;
        } catch (e) {
            console.log('cant stringify to check in cache', query);
        }
        return false;
    },

    addToCache: function (query, timeout) {
        try {
            var key = this._getCacheKey(query);
            var timeoutId;
            if (this._queryCache[key]) {
                timeoutId = this._queryCache[key].timeoutId
                if (timeoutId) {
                    clearTimeout(timeoutId);
                }
            }

            var self = this;
            if (typeof timeout === 'number') {
                timeoutId = setTimeout(function () {
                    delete self._queryCache[key];
                    $data.Trace.log('QueryCache cache timeout', key);
                }, timeout);
            } else {
                if (this._fix_Items.length >= this.__maxCacheSize()) {
                    var oldKey = this._fix_Items.shift();
                    delete self._queryCache[oldKey];
                    $data.Trace.log('QueryCache max cache size limit. Last removed: ', oldKey);
                }

                this._fix_Items.push(key);
            }

            this._queryCache[key] = {
                __count: query.__count,
                rawDataList: query.rawDataList,
                modelBinderConfig: query.modelBinderConfig,
                timeoutId: timeoutId
            }
            

            $data.Trace.log('QueryCache data inserted to cache');
        } catch (e) {
            console.log('cant stringify to cache', query);
        }
    },

    executeQuery: function (query, callBack) {
        try {
            var key = this._getCacheKey(query);
            $data.Trace.log('QueryCache load from cache', this._cacheKey, key);

            var cache = this._queryCache[key];

            query.__count = cache.__count;
            query.rawDataList = cache.rawDataList;
            query.modelBinderConfig = cache.modelBinderConfig;
        } catch (e) {
            callBack.error(e);
            return;
        }

        callBack.success(query);
    },

    _getCacheKey: function (query) {
        var frameTypeName = query.expression.getType().fullName;
        var key = frameTypeName + '_'
        if (query.expression.source instanceof $data.QueryCacheNS.WithCacheExpression)
            key += query.expression.source.source.getJSON();
        else
            key += query.expression.source.getJSON();

        return $data.QueryCache._keyHashCode(key);
    },
    __maxCacheSize: function () {
        return (!$data.defaults.maxQueryCacheSize || $data.defaults.maxQueryCacheSize < 0) ? 100 : $data.defaults.maxQueryCacheSize;
    }
}, {
    isCacheable: function (context, query) {
        ///<param name="context" type:="$data.EntityContext" />
        ///<param name="query" type:="$data.Query" optional="true" />

        try {
            var dummyKey = $data.QueryCache._generateCacheKey(context);
        } catch (e) {
            console.error('Cannot create unique cacheKey for context');
            return false;
        }

        if (context.enableQueryCache === false)
            return false;

        var isCacheable = $data.QueryCache._cacheTimeout(context, query) ? true : false;
        return isCacheable;
    },

    isInCache: function (context, query) {
        ///<param name="context" type:="$data.EntityContext" />
        ///<param name="query" type:="$data.Query" />

        if (this.isCacheable(context, query)) {
            var cf = $data.QueryCache._getQueryCache(context);
            if (cf.hasCacheForQuery(query)) {
                var withCache = $data.QueryCache._isForce(query);
                var forced = typeof withCache !== 'undefined';

                if (forced) {
                    return withCache;
                } else {
                    return true;
                }
            }
        }
        return false;
    },
    executeQuery: function (context, query, callback) {
        ///	<signature>
        ///     <param name="context" type:="$data.EntityContext" />
        ///     <param name="query" type:="$data.Query" />
        ///     <param name="query" type:="Function" />
        ///	</signature>
        ///	<signature>
        ///     <param name="context" type:="$data.EntityContext" />
        ///     <param name="query" type:="$data.Query" />
        ///     <param name="query" type:="Object" />
        ///	</signature>

        var cf = $data.QueryCache._getQueryCache(context);
        cf.executeQuery(query, {
            success: callback.success,
            error: function () {
                console.error('Cache execute error');
                console.error(arguments);
                context.storageProvider.executeQuery(query, callback);
            }
        });
    },
    reset: function (context) {
        ///<param name="context" type:="$data.EntityContext" />

        try {
            var contextType = context.getType();
            var key = $data.QueryCache._generateCacheKey(context);

            if (contextType._queryCacheValues && contextType._queryCacheValues[key]) {
                contextType._queryCacheValues[key].reset();
            }
        } catch (e) {

        }
    },
    addToCache: function (context, query) {
        ///<param name="context" type:="$data.EntityContext" />
        ///<param name="query" type:="$data.Query" />

        var cf = $data.QueryCache._getQueryCache(context);
        if (!cf.hasCacheForQuery(query) && $data.QueryCache._isForce(query) !== false) {
            cf.addToCache(query, $data.QueryCache._cacheTimeout(context, query));
        }
    },

    _getQueryCache: function (context) {
        var contextType = context.getType();
        //var provider = context.storageProvider.getType();
        //var key = provider.fullName + '_' + contextType.fullName + '_' + JSON.stringify(context.storageProvider.providerConfiguration);
        var key = $data.QueryCache._generateCacheKey(context);

        contextType._queryCacheValues = contextType._queryCacheValues || {};
        contextType._queryCacheValues[key] = contextType._queryCacheValues[key] || new $data.QueryCache(contextType, key);
        return contextType._queryCacheValues[key];
    },
    _generateCacheKey: function (context) {
        var contextType = context.getType();
        var provider = context.storageProvider.getType();
        var key = provider.fullName + '_' + contextType.fullName + '_' + JSON.stringify(context.storageProvider.providerConfiguration);
        return $data.QueryCache._keyHashCode(key);
    },
    _isForce: function (query) {
        if (query && query.expression.source instanceof $data.QueryCacheNS.WithCacheExpression) {
            return query.expression.source.value.value;
        }
        return undefined;
    },
    _cacheTimeout: function (context, query) {
        return $data.QueryCache._isForce(query) || context.queryCache || $data.defaults.queryCache;
    },
    _keyHashCode: function (key) {
        if(typeof key !== 'string') return 0;

        var hash = 0, i, charC;
        if (key.length == 0) return hash;
        for (i = 0; i < key.length; i++) {
            charC = key.charCodeAt(i);
            hash = ((hash << 5) - hash) + charC;
            hash = hash & hash;
        }
        return hash;
    },
    _maxCacheSize: function () {
        return !$data.defaults.maxQueryCacheSize || $data.defaults.maxQueryCacheSize < 0 ? 100 : $data.defaults.maxQueryCacheSize;
    },
    __allQuerySize: { type: 'int', value: 0 }
});

$data.EntityContext.addMember('cacheReset', function () {
    $data.QueryCache.reset(this);
});

$C('$data.QueryCacheNS.WithCacheExpression', $data.Expressions.ExpressionNode, null, {
    constructor: function (source, expression) {
        this.source = source;
        this.value = expression;
    },
    nodeType: { value: 'WithCache', enumerable: true }
});

$data.Expressions.EntityExpressionVisitor.addMember('VisitWithCacheExpression', function (expression, context) {
    var newExpression = this.Visit(expression.source, context);
    //var value = this.Visit(expression.value, context);
    if (newExpression !== expression.source /*|| value !== expression.value*/) {
        return new $data.QueryCacheNS.WithCacheExpression(newExpression, expression.value);
    }
    return expression;
});

$data.Queryable.addMember('withCache', function (isCache) {
    ///	<signature>
    ///     <param name="isCache" type:="number" />
    ///	</signature>
    ///	<signature>
    ///     <param name="isCache" type:="boolean" />
    ///	</signature>

    if (Guard.isNullOrUndefined(isCache)) isCache = true;
    var cacheValue = typeof isCache === 'number' ? isCache : Container.convertTo(isCache, $data.Boolean)
        , cacheType = typeof cacheValue;

    var constExp = Container.createConstantExpression(cacheValue, cacheType);
    var exp = new $data.QueryCacheNS.WithCacheExpression(this.expression, constExp);
    return Container.createQueryable(this, exp);
});

$data.Queryable.addMember('noCache', function () {
    return this.withCache(false);
});